mod panics {
    use super::*;
    #[test]
    #[should_panic(expected = "field name collision")]
    fn flatten_name_collision() {
        #[derive(Facet)]
        struct Collider {
            x: u32,
        }
        #[derive(Facet)]
        struct HasCollision {
            x: u32,
            #[facet(flatten)]
            inner: Collider,
        }
        kajit::compile_decoder(HasCollision::SHAPE, &kajit::json::KajitJson);
    }
}
mod postreg {
    use super::*;
    #[test]
    fn vec_scalar_large_hotpath_asserts() {
        let artifacts = codegen_artifacts::<ScalarVec, _>(&kajit::postcard::KajitPostcard);
        assert!(
            artifacts.ir_text.contains("theta") || artifacts.ir_text.contains("apply @"),
            "expected loop form (`theta`) or outlined loop body (`apply`) in IR"
        );
        assert!(
            artifacts.cfg_text.contains("branch_if"),
            "expected loop backedge in CFG-MIR"
        );
        assert!(
            artifacts.cfg_text.contains("call_intrinsic"),
            "expected intrinsic-heavy vec decode path in CFG-MIR"
        );
        assert!(
            artifacts.edits <= 128,
            "expected edit budget <= 128, got {}",
            artifacts.edits
        );
    }
}
